// 205_SOLAR_BACKUP_DIMENSIONAMENTO_FOTOVOLTAICO
const consumo_mensal_kwh = $input.item.json.conta?.consumo_mensal_kwh || 0;
// A geração mensal estimada por kWp deve vir de tabela configurável por região.
// Placeholder: 120 kWh/mês por kWp
const geracao_mensal_estimada_por_kwp = 120; 

const sistema_solar_kwp_preliminar = consumo_mensal_kwh / geracao_mensal_estimada_por_kwp;

$input.item.json.sistema_solar_kwp_preliminar = parseFloat(sistema_solar_kwp_preliminar.toFixed(2));

return $input.item;
